-- Generated SQL for global_unit=1 (stage=1 unit_local=1 unit_id=101)
INSERT INTO `que_choice_py_1` (`q_id`, `unit_id`, `title`, `text`, `options`, `answer`, `hints`, `explanation`, `example`) VALUES

(1, 101, '打印问候语', '作为Python新手，你想向编程世界打招呼，但忘了语法，该选哪个？', '[\\\"print Hello World\\\", \\\"print(''Hello World'')\\\", \\\"echo ''Hello World''\\\", \\\"printf(''Hello World'')\\\"]', 'B', '[\\\"在Python中，打印使用print函数。\\\", \\\"print函数需要括号和字符串。\\\", \\\"正确语法是print(''Hello World'')。\\\"]', '在Python中，使用print()函数来输出内容，字符串需要用引号括起来。', '例如，print(''你好，Python！'') 会输出 ''你好，Python！''。'),
(2, 101, '多参数打印', '你想同时打印名字和年龄，用逗号分隔，但代码总出问题，该怎么写？', '[\\\"print(''Name'', ''Age'')\\\", \\\"print(''Name'' + ''Age'')\\\", \\\"print(''Name'', ''Age'', sep='','')\\\", \\\"print(''Name''; ''Age'')\\\"]', 'C', '[\\\"print可以接受多个参数，默认用空格分隔。\\\", \\\"使用sep参数可以改变分隔符。\\\", \\\"正确选项是使用sep='',''来用逗号分隔。\\\"]', 'print函数可以接受多个参数，默认用空格分隔，但通过sep参数可以指定其他分隔符。', 'print(''Alice'', 25, sep='': '') 会输出 ''Alice: 25''。'),
(3, 101, '控制换行', '你想让两个print语句输出在同一行，避免换行尴尬，该设置什么参数？', '[\\\"end=''''\\\", \\\"sep=''''\\\", \\\"newline=False\\\", \\\"break=''''\\\"]', 'A', '[\\\"print默认以换行符结尾。\\\", \\\"end参数控制print结尾的字符。\\\", \\\"设置end=''''可以让输出不换行。\\\"]', 'print函数的end参数默认为''\n''，即换行。设置为空字符串可以避免换行。', 'print(''Hello'', end=''''); print(''World'') 会输出 ''HelloWorld''。'),
(6, 101, 'print的返回值', '在Python中，你赋值print(''Hi'')给变量，结果变量是什么？', '[\\\"输出的字符串''Hi''\\\", \\\"None\\\", \\\"True\\\", \\\"0\\\"]', 'B', '[\\\"print是一个函数，但它主要作用是输出。\\\", \\\"在Python中，函数如果没有return语句，默认返回None。\\\", \\\"print函数返回None。\\\"]', 'print函数用于输出内容到标准输出，但它本身返回None。', 'result = print(''Hello''); print(result) 会先输出''Hello''，然后输出''None''。'),
(7, 101, '转义字符辨析', '你想在字符串中包含双引号，避免语法错误，该使用哪个转义字符？', '[\\\"\\\\\\"\\\", \\\"\\''\\\", \\\"\\\\\\\", \\\"\\n\\\"]', 'A', '[\\\"在字符串中，双引号需要转义以避免结束字符串。\\\", \\\"使用反斜杠来转义特殊字符。\\\", \\\"\\\\\\"表示一个双引号字符。\\\"]', '在字符串中，如果要包含双引号，需要使用转义字符\\\\"。', 'print(\\\"他说：\\\\"你好\\\\"\\\") 会输出：他说：\\\"你好\\\"。'),
(8, 101, '变量与打印', '你有一个变量x=5，想打印''x的值是5''，但代码报错，该用哪个语句？', '[\\\"print(''x的值是'', x)\\\", \\\"print(''x的值是'' + x)\\\", \\\"print(''x的值是'' + str(x))\\\", \\\"print(f''x的值是{x}'')\\\"]', 'C', '[\\\"print可以打印多个参数，但字符串和数字不能直接相加。\\\", \\\"需要使用str()函数将数字转换为字符串。\\\", \\\"或者使用f-string格式化。\\\"]', '在Python中，字符串和数字不能直接连接，需要使用str()转换或格式化字符串。', 'x=10; print(''值为：'' + str(x)) 输出 ''值为：10''。'),
(11, 101, '语句结束符', '在Python中，语句通常以什么结束？别被其他语言带偏了！', '[\\\"分号\\\", \\\"换行符\\\", \\\"逗号\\\", \\\"括号\\\"]', 'B', '[\\\"Python使用缩进和换行来定义代码块。\\\", \\\"语句通常以换行结束，分号可选。\\\", \\\"正确是换行符。\\\"]', 'Python语句以换行符结束，但可以使用分号在同一行写多个语句。', 'x=5; y=10  # 使用分号分隔两个语句在同一行。'),
(12, 101, '打印与运算', '你写了print(2+3)，期待输出数学结果，它会输出什么？', '[\\\"''2+3''\\\", \\\"5\\\", \\\"23\\\", \\\"错误\\\"]', 'B', '[\\\"print可以打印表达式的结果。\\\", \\\"2+3是一个表达式，值为5。\\\", \\\"print会输出表达式的值。\\\"]', 'print函数会计算括号内的表达式并输出结果，所以print(2+3)输出5。', 'print(10/2) 输出 5.0。'),
(13, 101, '常见错误', '以下哪个语句在Python 3中会导致语法错误，让你抓狂？', '[\\\"print ''Hello''\\\", \\\"print(''Hello'')\\\", \\\"print(\\\\"Hello\\\\")\\\", \\\"print(''Hello'', end='''')\\\"]', 'A', '[\\\"在Python 3中，print是一个函数，必须使用括号。\\\", \\\"没有括号的print语句在Python 2中有效，但在Python 3中无效。\\\", \\\"正确语法需要括号。\\\"]', '在Python 3中，print是一个内置函数，必须使用括号调用，否则会语法错误。', '在Python 2中，print ''Hello'' 是有效的，但在Python 3中必须写为 print(''Hello'')。');

INSERT INTO `que_fill_py_1` (`q_id`, `unit_id`, `title`, `text`, `input`, `output`, `code`, `options`, `answer`, `explanation`, `example`) VALUES

(4, 101, '转义字符填空', '代码中使用了转义字符来让''Hello''和''World''分两行输出，请填空。', NULL, '[\\\"Hello\\\", \\\"World\\\"]', '{\\\"segments\\\":[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(''Hello\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"World'')\\\"}]}]}', '[\\\"\\n\\\", \\\"\\t\\\", \\\" \\\", \\\"+\\\"]', '[1]', '转义字符\n表示换行，所以''Hello\nWorld''会输出两行。', 'print(''Line1\nLine2'') 输出两行：Line1 和 Line2。'),
(5, 101, '分隔符设置', '你想用逗号分隔打印水果列表，但代码不完整，请填空。', NULL, '[\\\"apple,banana,cherry\\\"]', '{\\\"segments\\\":[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(''apple'',''banana'',''cherry'', sep=\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\")\\\"}]}]}', '[\\\"'',''\\\", \\\"'' ''\\\", \\\"''\\t''\\\", \\\"'':''\\\", \\\"'';''\\\"]', '[1]', 'sep参数指定了print中多个参数之间的分隔符，设置为'',''时用逗号分隔。', 'print(1,2,3, sep=''-'') 输出 ''1-2-3''。'),
(9, 101, '多行输出代码', '以下代码应该输出一个三行的问候语，但第二行填空才能正确换行。', NULL, '[\\\"第一行：Hello\\\", \\\"第二行：World\\\", \\\"第三行：Python\\\"]', '{\\\"segments\\\":[{\\\"type\\\":\\\"code_block\\\",\\\"lines\\\":[{\\\"type\\\":\\\"code_line\\\",\\\"value\\\":\\\"print(''第一行：Hello'')\\\"},{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(''第二行：World'', \\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\")\\\"}]},{\\\"type\\\":\\\"code_line\\\",\\\"value\\\":\\\"print(''第三行：Python'')\\\"}]}]}', '[\\\"end=''\\n''\\\", \\\"end=''''\\\", \\\"sep='' ''\\\", \\\"end=''\\t''\\\"]', '[1]', '默认end=''\n''已经换行，但这里填空保持默认或明确设置，答案end=''\n''确保第二行后换行。', 'print(''A'', end=''\n''); print(''B'') 输出两行：A 和 B。'),
(10, 101, '打印多行字符串', '使用一个print语句打印多行文本，但转义字符填空了，请补全。', NULL, '[\\\"Line 1\\\", \\\"Line 2\\\", \\\"Line 3\\\"]', '{\\\"segments\\\":[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(''Line 1\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"Line 2\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"Line 3'')\\\"}]}]}', '[\\\"\\n\\\", \\\" \\\", \\\"\\t\\\", \\\"'': ''\\\"]', '[1, 1]', '在字符串中使用转义字符\n可以插入换行，使一个print语句输出多行。', 'print(''A\nB\nC'') 输出三行：A, B, C。'),
(14, 101, '综合打印代码', '以下代码模拟打印一个进度条，但分隔符和结尾填空了，请补全。', NULL, '[\\\"[====     ] 50%\\\"]', '{\\\"segments\\\":[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(''['', ''===='', ''     '', '']'', sep=\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\", end=\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\")\\\"}]},{\\\"type\\\":\\\"code_block\\\",\\\"lines\\\":[{\\\"type\\\":\\\"code_line\\\",\\\"value\\\":\\\"print(''50%'')\\\"}]}]}', '[\\\"''''\\\", \\\"'' ''\\\", \\\"''\\n''\\\", \\\"''\\t''\\\", \\\"'': ''\\\"]', '[1, 2]', '设置sep=''''可以让多个参数之间无分隔，end='' ''设置结尾为空格，使下一print在同一行后输出。', 'print(''Hello'', ''World'', sep='''', end=''!''); print(''Done'') 输出 ''HelloWorld!Done''。'),
(15, 101, '转义字符组合', '打印一个包含引号和换行的字符串，但转义字符填空了，请补全。', NULL, '[\\\"他说:\\\\"你好！\\\\"\\\", \\\"然后走了。\\\"]', '{\\\"segments\\\":[{\\\"type\\\":\\\"code_inline\\\",\\\"parts\\\":[{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"print(''他说:\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":0},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"你好！\\\"},{\\\"type\\\":\\\"slot\\\",\\\"index\\\":1},{\\\"type\\\":\\\"code\\\",\\\"value\\\":\\\"然后走了。'')\\\"}]}]}', '[\\\"\\\\\\"\\\", \\\"\\n\\\", \\\"\\t\\\", \\\" \\\"]', '[1, 2]', '在字符串中，使用\\\\"来插入双引号，使用\n来换行。', 'print(\\\"第一行\n第二行\\\\"带引号\\\\"\\\") 输出两行，第二行包含引号。');